contracts/PizzaPartyAdvancedRandomness.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title PizzaPartyAdvancedRandomness
 * @dev Advanced randomness system with multi-party commit-reveal scheme
 * 
 * FEATURES:
 * - Multi-party commit-reveal randomness
 * - Entropy contribution from multiple sources
 * - Secure randomness generation
 * - Round-based randomness collection
 * - Anti-manipulation measures
 */
contract PizzaPartyAdvancedRandomness is ReentrancyGuard, Ownable, Pausable {

    // Round structure
    struct RandomnessRound {
        uint256 roundId;
        uint256 startTime;
        uint256 endTime;
        uint256 commitPhaseEnd;
        uint256 revealPhaseEnd;
        bytes32 finalSeed;
        bool isCompleted;
        uint256 totalContributors;
        uint256 totalEntropy;
        mapping(address => bytes32) commitments;
        mapping(address => bool) hasRevealed;
        mapping(address => bool) hasCommitted;
        address[] contributors;
    }

    // Contributor data
    struct ContributorData {
        uint256 totalContributions;
        uint256 successfulReveals;
        uint256 failedReveals;
        uint256 lastContribution;
        bool isBlacklisted;
        uint256 reputation;
    }

    // System constants
    uint256 public constant COMMIT_PHASE_DURATION = 1 hours;
    uint256 public constant REVEAL_PHASE_DURATION = 30 minutes;
    uint256 public constant MIN_CONTRIBUTORS = 3;
    uint256 public constant MAX_CONTRIBUTORS = 50;
    uint256 public constant MIN_ENTROPY_BITS = 128;
    uint256 public constant REPUTATION_THRESHOLD = 10;

    // Round tracking
    mapping(uint256 => RandomnessRound) public randomnessRounds;
    uint256 public currentRoundId;
    uint256 public totalRounds;

    // Contributor tracking
    mapping(address => ContributorData) public contributorData;
    mapping(address => bool) public blacklistedContributors;

    // Global statistics
    uint256 public totalEntropyGenerated;
    uint256 public totalContributors;
    uint256 public activeContributors;

    // Events
    event RoundStarted(
        uint256 indexed roundId,
        uint256 startTime,
        uint256 commitPhaseEnd,
        uint256 revealPhaseEnd
    );

    event EntropyCommitted(
        uint256 indexed roundId,
        address indexed contributor,
        bytes32 commitment,
        uint256 timestamp
    );

    event EntropyRevealed(
        uint256 indexed roundId,
        address indexed contributor,
        bytes32 entropy,
        uint256 timestamp
    );

    event RoundCompleted(
        uint256 indexed roundId,
        bytes32 finalSeed,
        uint256 totalContributors,
        uint256 totalEntropy,
        uint256 timestamp
    );

    event ContributorBlacklisted(address indexed contributor, bool blacklisted);

    event ReputationUpdated(
        address indexed contributor,
        uint256 oldReputation,
        uint256 newReputation
    );

    // Modifiers
    modifier notBlacklisted(address contributor) {
        require(!blacklistedContributors[contributor], "Contributor is blacklisted");
        require(!contributorData[contributor].isBlacklisted, "Contributor is blacklisted");
        _;
    }

    modifier roundExists(uint256 roundId) {
        require(roundId <= totalRounds, "Round does not exist");
        _;
    }

    modifier roundActive(uint256 roundId) {
        require(roundId == currentRoundId, "Round is not active");
        require(!randomnessRounds[roundId].isCompleted, "Round is completed");
        _;
    }

    modifier inCommitPhase(uint256 roundId) {
        require(block.timestamp <= randomnessRounds[roundId].commitPhaseEnd, "Commit phase ended");
        _;
    }

    modifier inRevealPhase(uint256 roundId) {
        require(
            block.timestamp > randomnessRounds[roundId].commitPhaseEnd &&
            block.timestamp <= randomnessRounds[roundId].revealPhaseEnd,
            "Not in reveal phase"
        );
        _;
    }

    modifier notCommitted(uint256 roundId, address contributor) {
        require(!randomnessRounds[roundId].hasCommitted[contributor], "Already committed");
        _;
    }

    modifier notRevealed(uint256 roundId, address contributor) {
        require(!randomnessRounds[roundId].hasRevealed[contributor], "Already revealed");
        _;
    }

    constructor() Ownable(msg.sender) {
        currentRoundId = 1;
        totalRounds = 0;
    }

    /**
     * @dev Start a new randomness round
     */
    function startNewRound() external onlyOwner whenNotPaused {
        require(
            totalRounds == 0 || randomnessRounds[currentRoundId].isCompleted,
            "Current round not completed"
        );

        uint256 roundId = currentRoundId;
        uint256 startTime = block.timestamp;
        uint256 commitPhaseEnd = startTime + COMMIT_PHASE_DURATION;
        uint256 revealPhaseEnd = commitPhaseEnd + REVEAL_PHASE_DURATION;

        RandomnessRound storage round = randomnessRounds[roundId];
        round.roundId = roundId;
        round.startTime = startTime;
        round.endTime = revealPhaseEnd;
        round.commitPhaseEnd = commitPhaseEnd;
        round.revealPhaseEnd = revealPhaseEnd;
        round.isCompleted = false;
        round.totalContributors = 0;
        round.totalEntropy = 0;

        totalRounds++;

        emit RoundStarted(roundId, startTime, commitPhaseEnd, revealPhaseEnd);
    }

    /**
     * @dev Commit entropy to current round
     */
    function commitEntropy(bytes32 commitment) 
        external 
        nonReentrant 
        whenNotPaused 
        roundActive(currentRoundId)
        inCommitPhase(currentRoundId)
        notCommitted(currentRoundId, msg.sender)
        notBlacklisted(msg.sender)
    {
        require(commitment != bytes32(0), "Invalid commitment");

        RandomnessRound storage round = randomnessRounds[currentRoundId];

        // Check contributor limit
        require(round.totalContributors < MAX_CONTRIBUTORS, "Max contributors reached");

        // Record commitment
        round.commitments[msg.sender] = commitment;
        round.hasCommitted[msg.sender] = true;
        round.contributors.push(msg.sender);
        round.totalContributors++;

        // Update contributor data
        ContributorData storage contributor = contributorData[msg.sender];
        contributor.totalContributions++;
        contributor.lastContribution = block.timestamp;

        // Check for new contributor
        if (contributor.totalContributions == 1) {
            totalContributors++;
            activeContributors++;
        }

        emit EntropyCommitted(currentRoundId, msg.sender, commitment, block.timestamp);
    }

    /**
     * @dev Reveal entropy for current round
     */
    function revealEntropy(bytes32 entropy, bytes32 salt) 
        external 
        nonReentrant 
        whenNotPaused 
        roundActive(currentRoundId)
        inRevealPhase(currentRoundId)
        notRevealed(currentRoundId, msg.sender)
    {
        require(randomnessRounds[currentRoundId].hasCommitted[msg.sender], "No commitment found");

        // Verify commitment
        bytes32 expectedCommitment = keccak256(abi.encodePacked(entropy, salt, msg.sender));
        require(
            expectedCommitment == randomnessRounds[currentRoundId].commitments[msg.sender],
            "Invalid entropy or salt"
        );

        RandomnessRound storage round = randomnessRounds[currentRoundId];

        // Record reveal
        round.hasRevealed[msg.sender] = true;

        // Add entropy to total
        round.totalEntropy = uint256(keccak256(abi.encodePacked(
            round.totalEntropy,
            entropy,
            msg.sender
        )));

        // Update contributor data
        ContributorData storage contributor = contributorData[msg.sender];
        contributor.successfulReveals++;
        contributor.reputation += 1;

        emit EntropyRevealed(currentRoundId, msg.sender, entropy, block.timestamp);

        // Check if round should be completed
        if (round.totalContributors >= MIN_CONTRIBUTORS) {
            _completeRound(currentRoundId);
        }
    }

    /**
     * @dev Complete round manually (owner only)
     */
    function completeRound(uint256 roundId) 
        external 
        onlyOwner 
        roundExists(roundId)
    {
        require(!randomnessRounds[roundId].isCompleted, "Round already completed");
        _completeRound(roundId);
    }

    /**
     * @dev Get current round info
     */
    function getCurrentRoundInfo() external view returns (
        uint256 roundId,
        uint256 startTime,
        uint256 commitPhaseEnd,
        uint256 revealPhaseEnd,
        bool isCompleted,
        uint256 _totalContributors,
        uint256 totalEntropy
    ) {
        RandomnessRound storage round = randomnessRounds[currentRoundId];
        return (
            round.roundId,
            round.startTime,
            round.commitPhaseEnd,
            round.revealPhaseEnd,
            round.isCompleted,
            round.totalContributors,
            round.totalEntropy
        );
    }

    /**
     * @dev Get round contributors
     */
    function getRoundContributors(uint256 roundId) 
        external 
        view 
        roundExists(roundId)
        returns (address[] memory)
    {
        return randomnessRounds[roundId].contributors;
    }

    /**
     * @dev Get contributor data
     */
    function getContributorData(address contributor) external view returns (ContributorData memory) {
        return contributorData[contributor];
    }

    /**
     * @dev Get final seed for round
     */
    function getFinalSeed(uint256 roundId) 
        external 
        view 
        roundExists(roundId)
        returns (bytes32)
    {
        require(randomnessRounds[roundId].isCompleted, "Round not completed");
        return randomnessRounds[roundId].finalSeed;
    }

    /**
     * @dev Blacklist/unblacklist contributor
     */
    function setContributorBlacklist(address contributor, bool blacklisted) external onlyOwner {
        blacklistedContributors[contributor] = blacklisted;
        contributorData[contributor].isBlacklisted = blacklisted;
        emit ContributorBlacklisted(contributor, blacklisted);
    }

    /**
     * @dev Update contributor reputation
     */
    function updateReputation(address contributor, uint256 newReputation) external onlyOwner {
        uint256 oldReputation = contributorData[contributor].reputation;
        contributorData[contributor].reputation = newReputation;
        emit ReputationUpdated(contributor, oldReputation, newReputation);
    }

    /**
     * @dev Emergency pause/unpause
     */
    function emergencyPause(bool pause) external onlyOwner {
        if (pause) {
            _pause();
        } else {
            _unpause();
        }
    }

    /**
     * @dev Generate random number from seed
     */
    function generateRandomNumber(bytes32 seed, uint256 maxValue) external view returns (uint256) {
        require(maxValue > 0, "Max value must be positive");
        return uint256(keccak256(abi.encodePacked(seed, block.timestamp))) % maxValue;
    }

    /**
     * @dev Internal function to complete round
     */
    function _completeRound(uint256 roundId) internal {
        RandomnessRound storage round = randomnessRounds[roundId];

        // Calculate final seed
        bytes32 finalSeed = keccak256(abi.encodePacked(
            round.totalEntropy,
            round.roundId,
            block.timestamp,
            block.prevrandao
        ));

        round.finalSeed = finalSeed;
        round.isCompleted = true;

        // Update global stats
        totalEntropyGenerated += round.totalEntropy;

        // Move to next round
        currentRoundId++;

        emit RoundCompleted(
            roundId,
            finalSeed,
            round.totalContributors,
            round.totalEntropy,
            block.timestamp
        );
    }

    /**
     * @dev Internal function to check if entropy is sufficient
     */
    function _isEntropySufficient(bytes32 entropy) internal pure returns (bool) {
        // Count non-zero bits in entropy
        uint256 nonZeroBits = 0;
        for (uint256 i = 0; i < 256; i++) {
            if (uint256(entropy) & (1 << i) != 0) {
                nonZeroBits++;
            }
        }

        return nonZeroBits >= MIN_ENTROPY_BITS;
    }
}

contracts/PizzaPartyAnalytics.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title PizzaPartyAnalytics
 * @dev Analytics and batch processing system for Pizza Party game
 * 
 * FEATURES:
 * - Batch player processing
 * - Gas optimization
 * - Game statistics tracking
 * - Performance analytics
 * - Data aggregation
 */
contract PizzaPartyAnalytics is ReentrancyGuard, Ownable, Pausable {

    // VMF Token contract
    IERC20 public immutable vmfToken;

    // Analytics data structure
    struct GameAnalytics {
        uint256 totalPlayers;
        uint256 activePlayers;
        uint256 totalEntries;
        uint256 totalRewards;
        uint256 averageEntryFee;
        uint256 gasUsed;
        uint256 timestamp;
        uint256 blockNumber;
    }

    // Player batch structure
    struct PlayerBatch {
        address[] players;
        uint256[] entryCounts;
        uint256[] rewardAmounts;
        uint256 timestamp;
        bool isProcessed;
    }

    // Performance metrics
    struct PerformanceMetrics {
        uint256 totalGasUsed;
        uint256 averageGasPerTransaction;
        uint256 totalTransactions;
        uint256 optimizationSavings;
        uint256 lastOptimization;
    }

    // Analytics tracking
    mapping(uint256 => GameAnalytics) public gameAnalytics;
    mapping(uint256 => PlayerBatch) public playerBatches;
    mapping(address => uint256) public playerLastActivity;
    mapping(address => uint256) public playerTotalEntries;
    mapping(address => uint256) public playerTotalRewards;

    // Performance tracking
    PerformanceMetrics public performanceMetrics;

    // Batch processing
    uint256 public currentBatchId;
    uint256 public totalBatches;
    uint256 public batchSize;
    uint256 public gasOptimizationThreshold;

    // Global statistics
    uint256 public totalPlayersProcessed;
    uint256 public totalGasOptimized;
    uint256 public lastAnalyticsUpdate;

    // Events
    event AnalyticsUpdated(
        uint256 indexed analyticsId,
        uint256 totalPlayers,
        uint256 activePlayers,
        uint256 totalEntries,
        uint256 totalRewards,
        uint256 gasUsed
    );

    event BatchProcessed(
        uint256 indexed batchId,
        address[] players,
        uint256 totalEntries,
        uint256 totalRewards,
        uint256 gasUsed
    );

    event GasOptimizationCompleted(
        uint256 timestamp,
        uint256 gasSaved,
        uint256 optimizationThreshold
    );

    event PlayerActivityRecorded(
        address indexed player,
        uint256 entryCount,
        uint256 rewardAmount,
        uint256 timestamp
    );

    event BatchSizeUpdated(uint256 oldSize, uint256 newSize);

    event GasThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);

    // Modifiers
    modifier validBatch(uint256 batchId) {
        require(batchId <= totalBatches, "Invalid batch ID");
        _;
    }

    modifier batchNotProcessed(uint256 batchId) {
        require(!playerBatches[batchId].isProcessed, "Batch already processed");
        _;
    }

    constructor(address _vmfToken) Ownable(msg.sender) {
        require(_vmfToken != address(0), "Invalid VMF token address");
        vmfToken = IERC20(_vmfToken);

        // Initialize batch processing parameters
        batchSize = 50;
        gasOptimizationThreshold = 1000000; // 1M gas
        currentBatchId = 1;
        totalBatches = 0;
    }

    /**
     * @dev Record player activity
     */
    function recordPlayerActivity(
        address player,
        uint256 entryCount,
        uint256 rewardAmount
    ) external onlyOwner nonReentrant whenNotPaused {
        require(player != address(0), "Invalid player address");

        // Update player data
        playerLastActivity[player] = block.timestamp;
        playerTotalEntries[player] += entryCount;
        playerTotalRewards[player] += rewardAmount;

        // Update global stats
        totalPlayersProcessed++;

        emit PlayerActivityRecorded(player, entryCount, rewardAmount, block.timestamp);

        // Check for gas optimization
        if (gasleft() < gasOptimizationThreshold) {
            _optimizeGasUsage();
        }
    }

    /**
     * @dev Process batch of players
     */
    function processPlayerBatch(
        address[] calldata players,
        uint256[] calldata entryCounts,
        uint256[] calldata rewardAmounts
    ) external onlyOwner nonReentrant whenNotPaused {
        require(players.length > 0, "Empty batch");
        require(players.length == entryCounts.length, "Array length mismatch");
        require(players.length == rewardAmounts.length, "Array length mismatch");
        require(players.length <= batchSize, "Batch too large");

        uint256 batchId = currentBatchId;
        uint256 gasStart = gasleft();

        // Create batch
        PlayerBatch storage batch = playerBatches[batchId];
        batch.players = players;
        batch.entryCounts = entryCounts;
        batch.rewardAmounts = rewardAmounts;
        batch.timestamp = block.timestamp;
        batch.isProcessed = true;

        // Process each player
        uint256 totalEntries = 0;
        uint256 totalRewards = 0;

        for (uint256 i = 0; i < players.length; i++) {
            address player = players[i];
            uint256 entryCount = entryCounts[i];
            uint256 rewardAmount = rewardAmounts[i];

            // Update player data
            playerLastActivity[player] = block.timestamp;
            playerTotalEntries[player] += entryCount;
            playerTotalRewards[player] += rewardAmount;

            totalEntries += entryCount;
            totalRewards += rewardAmount;
        }

        // Update global stats
        totalPlayersProcessed += players.length;
        totalBatches++;
        currentBatchId++;

        // Calculate gas used
        uint256 gasUsed = gasStart - gasleft();
        performanceMetrics.totalGasUsed += gasUsed;
        performanceMetrics.totalTransactions++;
        performanceMetrics.averageGasPerTransaction = 
            performanceMetrics.totalGasUsed / performanceMetrics.totalTransactions;

        emit BatchProcessed(batchId, players, totalEntries, totalRewards, gasUsed);
    }

    /**
     * @dev Update game analytics
     */
    function updateGameAnalytics(
        uint256 totalPlayers,
        uint256 activePlayers,
        uint256 totalEntries,
        uint256 totalRewards,
        uint256 averageEntryFee
    ) external onlyOwner nonReentrant whenNotPaused {
        uint256 analyticsId = lastAnalyticsUpdate + 1;
        uint256 gasStart = gasleft();

        GameAnalytics storage analytics = gameAnalytics[analyticsId];
        analytics.totalPlayers = totalPlayers;
        analytics.activePlayers = activePlayers;
        analytics.totalEntries = totalEntries;
        analytics.totalRewards = totalRewards;
        analytics.averageEntryFee = averageEntryFee;
        analytics.gasUsed = gasStart - gasleft();
        analytics.timestamp = block.timestamp;
        analytics.blockNumber = block.number;

        lastAnalyticsUpdate = analyticsId;

        emit AnalyticsUpdated(
            analyticsId,
            totalPlayers,
            activePlayers,
            totalEntries,
            totalRewards,
            analytics.gasUsed
        );
    }

    /**
     * @dev Get player analytics
     */
    function getPlayerAnalytics(address player) external view returns (
        uint256 lastActivity,
        uint256 totalEntries,
        uint256 totalRewards
    ) {
        return (
            playerLastActivity[player],
            playerTotalEntries[player],
            playerTotalRewards[player]
        );
    }

    /**
     * @dev Get batch info
     */
    function getBatchInfo(uint256 batchId) 
        external 
        view 
        validBatch(batchId)
        returns (
            address[] memory players,
            uint256[] memory entryCounts,
            uint256[] memory rewardAmounts,
            uint256 timestamp,
            bool isProcessed
        )
    {
        PlayerBatch storage batch = playerBatches[batchId];
        return (
            batch.players,
            batch.entryCounts,
            batch.rewardAmounts,
            batch.timestamp,
            batch.isProcessed
        );
    }

    /**
     * @dev Get performance metrics
     */
    function getPerformanceMetrics() external view returns (PerformanceMetrics memory) {
        return performanceMetrics;
    }

    /**
     * @dev Update batch size
     */
    function updateBatchSize(uint256 newBatchSize) external onlyOwner {
        require(newBatchSize > 0, "Batch size must be positive");
        require(newBatchSize <= 1000, "Batch size too large");

        uint256 oldSize = batchSize;
        batchSize = newBatchSize;

        emit BatchSizeUpdated(oldSize, newBatchSize);
    }

    /**
     * @dev Update gas optimization threshold
     */
    function updateGasThreshold(uint256 newThreshold) external onlyOwner {
        uint256 oldThreshold = gasOptimizationThreshold;
        gasOptimizationThreshold = newThreshold;

        emit GasThresholdUpdated(oldThreshold, newThreshold);
    }

    /**
     * @dev Emergency pause/unpause
     */
    function emergencyPause(bool pause) external onlyOwner {
        if (pause) {
            _pause();
        } else {
            _unpause();
        }
    }

    /**
     * @dev Get analytics summary
     */
    function getAnalyticsSummary() external view returns (
        uint256 _totalPlayersProcessed,
        uint256 _totalBatches,
        uint256 _totalGasOptimized,
        uint256 _lastAnalyticsUpdate,
        uint256 _currentBatchId
    ) {
        return (
            totalPlayersProcessed,
            totalBatches,
            totalGasOptimized,
            lastAnalyticsUpdate,
            currentBatchId
        );
    }

    /**
     * @dev Internal function to optimize gas usage
     */
    function _optimizeGasUsage() internal {
        uint256 gasStart = gasleft();

        // Perform gas optimization operations
        // This could include:
        // - Clearing unused storage
        // - Optimizing data structures
        // - Batching operations

        uint256 gasUsed = gasStart - gasleft();
        uint256 gasSaved = gasOptimizationThreshold - gasUsed;

        if (gasSaved > 0) {
            totalGasOptimized += gasSaved;
            performanceMetrics.optimizationSavings += gasSaved;
            performanceMetrics.lastOptimization = block.timestamp;

            emit GasOptimizationCompleted(block.timestamp, gasSaved, gasOptimizationThreshold);
        }
    }

    /**
     * @dev Calculate optimal batch size based on gas usage
     */
    function calculateOptimalBatchSize() external view returns (uint256) {
        if (performanceMetrics.totalTransactions == 0) {
            return batchSize;
        }

        uint256 averageGas = performanceMetrics.averageGasPerTransaction;
        uint256 gasLimit = block.gaslimit;
        uint256 targetGasUsage = gasLimit / 2; // Use 50% of gas limit

        uint256 optimalSize = targetGasUsage / averageGas;

        // Ensure reasonable bounds
        if (optimalSize < 10) optimalSize = 10;
        if (optimalSize > 1000) optimalSize = 1000;

        return optimalSize;
    }
}

contracts/PizzaPartyDynamicPricing.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title PizzaPartyDynamicPricing
 * @dev Dynamic pricing system for Pizza Party game
 * 
 * FEATURES:
 * - Dynamic entry fees based on VMF price
 * - Price oracle integration
 * - Fee calculation algorithms
 * - Price deviation protection
 * - Fee history tracking
 */
// Price oracle interface
interface IPriceOracle {
    function getVMFPrice() external view returns (uint256);
    function getLastUpdateTime() external view returns (uint256);
}

contract PizzaPartyDynamicPricing is ReentrancyGuard, Ownable, Pausable {

    // VMF Token contract
    IERC20 public immutable vmfToken;

    // Price oracle contract
    IPriceOracle public priceOracle;

    // Pricing structure
    struct PricingConfig {
        uint256 baseEntryFee; // Base entry fee in USD (18 decimals)
        uint256 maxPriceDeviation; // Maximum price deviation percentage
        uint256 priceUpdateThreshold; // Time threshold for price updates
        uint256 minEntryFee; // Minimum entry fee in VMF
        uint256 maxEntryFee; // Maximum entry fee in VMF
        uint256 feeMultiplier; // Fee multiplier for dynamic pricing
    }

    // Fee history structure
    struct FeeHistory {
        uint256 timestamp;
        uint256 vmfPrice;
        uint256 calculatedFee;
        uint256 actualFee;
        uint256 blockNumber;
    }

    // Pricing configuration
    PricingConfig public pricingConfig;

    // Fee history tracking
    mapping(uint256 => FeeHistory) public feeHistory;
    uint256 public feeHistoryCount;

    // Price tracking
    uint256 public lastVMFPrice;
    uint256 public lastPriceUpdate;
    uint256 public totalFeesCollected;
    uint256 public totalEntries;

    // Events
    event PricingConfigUpdated(
        uint256 baseEntryFee,
        uint256 maxPriceDeviation,
        uint256 priceUpdateThreshold,
        uint256 minEntryFee,
        uint256 maxEntryFee,
        uint256 feeMultiplier
    );

    event DynamicFeeCalculated(
        uint256 vmfPrice,
        uint256 calculatedFee,
        uint256 actualFee,
        uint256 timestamp
    );

    event PriceOracleUpdated(address indexed oldOracle, address indexed newOracle);

    event FeeCollected(
        address indexed user,
        uint256 feeAmount,
        uint256 vmfPrice,
        uint256 timestamp
    );

    // Modifiers
    modifier validPriceOracle() {
        require(address(priceOracle) != address(0), "Price oracle not set");
        _;
    }

    modifier priceNotStale() {
        require(
            block.timestamp - lastPriceUpdate <= pricingConfig.priceUpdateThreshold,
            "Price is stale"
        );
        _;
    }

    constructor(address _vmfToken, address _priceOracle) Ownable(msg.sender) {
        require(_vmfToken != address(0), "Invalid VMF token address");
        require(_priceOracle != address(0), "Invalid price oracle address");

        vmfToken = IERC20(_vmfToken);
        priceOracle = IPriceOracle(_priceOracle);

        // Initialize pricing configuration
        pricingConfig = PricingConfig({
            baseEntryFee: 1 * 10**18, // $1 USD
            maxPriceDeviation: 50, // 50%
            priceUpdateThreshold: 5 minutes,
            minEntryFee: 1 * 10**18, // 1 VMF minimum
            maxEntryFee: 1000 * 10**18, // 1000 VMF maximum
            feeMultiplier: 100 // 100% (1.0x)
        });

        // Initialize price tracking
        lastVMFPrice = priceOracle.getVMFPrice();
        lastPriceUpdate = block.timestamp;
    }

    /**
     * @dev Calculate dynamic entry fee
     */
    function calculateDynamicEntryFee() 
        external 
        view 
        validPriceOracle 
        returns (uint256 feeAmount, uint256 vmfPrice)
    {
        vmfPrice = priceOracle.getVMFPrice();
        feeAmount = _calculateFeeFromPrice(vmfPrice);

        // Apply bounds
        if (feeAmount < pricingConfig.minEntryFee) {
            feeAmount = pricingConfig.minEntryFee;
        } else if (feeAmount > pricingConfig.maxEntryFee) {
            feeAmount = pricingConfig.maxEntryFee;
        }

        return (feeAmount, vmfPrice);
    }

    /**
     * @dev Get current entry fee
     */
    function getCurrentEntryFee() external view returns (uint256) {
        (uint256 feeAmount,) = this.calculateDynamicEntryFee();
        return feeAmount;
    }

    /**
     * @dev Get VMF price from oracle
     */
    function getVMFPrice() external view validPriceOracle returns (uint256) {
        return priceOracle.getVMFPrice();
    }

    /**
     * @dev Update pricing configuration
     */
    function updatePricingConfig(
        uint256 _baseEntryFee,
        uint256 _maxPriceDeviation,
        uint256 _priceUpdateThreshold,
        uint256 _minEntryFee,
        uint256 _maxEntryFee,
        uint256 _feeMultiplier
    ) external onlyOwner {
        require(_baseEntryFee > 0, "Base entry fee must be positive");
        require(_maxPriceDeviation <= 100, "Max deviation cannot exceed 100%");
        require(_minEntryFee <= _maxEntryFee, "Min fee cannot exceed max fee");
        require(_feeMultiplier > 0, "Fee multiplier must be positive");

        pricingConfig = PricingConfig({
            baseEntryFee: _baseEntryFee,
            maxPriceDeviation: _maxPriceDeviation,
            priceUpdateThreshold: _priceUpdateThreshold,
            minEntryFee: _minEntryFee,
            maxEntryFee: _maxEntryFee,
            feeMultiplier: _feeMultiplier
        });

        emit PricingConfigUpdated(
            _baseEntryFee,
            _maxPriceDeviation,
            _priceUpdateThreshold,
            _minEntryFee,
            _maxEntryFee,
            _feeMultiplier
        );
    }

    /**
     * @dev Update price oracle
     */
    function updatePriceOracle(address _newOracle) external onlyOwner {
        require(_newOracle != address(0), "Invalid oracle address");

        address oldOracle = address(priceOracle);
        priceOracle = IPriceOracle(_newOracle);

        // Update price tracking
        lastVMFPrice = priceOracle.getVMFPrice();
        lastPriceUpdate = block.timestamp;

        emit PriceOracleUpdated(oldOracle, _newOracle);
    }

    /**
     * @dev Collect entry fee
     */
    function collectEntryFee(address user) 
        external 
        nonReentrant 
        whenNotPaused 
        validPriceOracle 
        priceNotStale 
        returns (uint256 feeAmount)
    {
        // Calculate dynamic fee
        uint256 vmfPrice;
        (feeAmount, vmfPrice) = this.calculateDynamicEntryFee();

        // Check price deviation
        require(
            _isPriceWithinDeviation(vmfPrice),
            "Price deviation too high"
        );

        // Transfer fee from user
        require(
            vmfToken.transferFrom(user, address(this), feeAmount),
            "Fee transfer failed"
        );

        // Update tracking
        totalFeesCollected += feeAmount;
        totalEntries++;

        // Update price tracking
        lastVMFPrice = vmfPrice;
        lastPriceUpdate = block.timestamp;

        // Record fee history
        _recordFeeHistory(vmfPrice, feeAmount, feeAmount);

        emit FeeCollected(user, feeAmount, vmfPrice, block.timestamp);

        return feeAmount;
    }

    /**
     * @dev Get fee history
     */
    function getFeeHistory(uint256 startIndex, uint256 count) 
        external 
        view 
        returns (FeeHistory[] memory)
    {
        require(startIndex < feeHistoryCount, "Invalid start index");

        uint256 endIndex = startIndex + count;
        if (endIndex > feeHistoryCount) {
            endIndex = feeHistoryCount;
        }

        FeeHistory[] memory history = new FeeHistory[](endIndex - startIndex);

        for (uint256 i = startIndex; i < endIndex; i++) {
            history[i - startIndex] = feeHistory[i];
        }

        return history;
    }

    /**
     * @dev Get pricing statistics
     */
    function getPricingStats() external view returns (
        uint256 _totalFeesCollected,
        uint256 _totalEntries,
        uint256 _averageFee,
        uint256 _lastVMFPrice,
        uint256 _lastPriceUpdate
    ) {
        _totalFeesCollected = totalFeesCollected;
        _totalEntries = totalEntries;
        _averageFee = totalEntries > 0 ? totalFeesCollected / totalEntries : 0;
        _lastVMFPrice = lastVMFPrice;
        _lastPriceUpdate = lastPriceUpdate;

        return (_totalFeesCollected, _totalEntries, _averageFee, _lastVMFPrice, _lastPriceUpdate);
    }

    /**
     * @dev Emergency pause/unpause
     */
    function emergencyPause(bool pause) external onlyOwner {
        if (pause) {
            _pause();
        } else {
            _unpause();
        }
    }

    /**
     * @dev Withdraw collected fees
     */
    function withdrawFees(address recipient) external onlyOwner {
        require(recipient != address(0), "Invalid recipient");

        uint256 balance = vmfToken.balanceOf(address(this));
        require(balance > 0, "No fees to withdraw");

        require(vmfToken.transfer(recipient, balance), "Fee withdrawal failed");
    }

    /**
     * @dev Internal function to calculate fee from price
     */
    function _calculateFeeFromPrice(uint256 vmfPrice) internal view returns (uint256) {
        if (vmfPrice == 0) {
            return pricingConfig.minEntryFee;
        }

        // Calculate fee: (baseEntryFee * feeMultiplier) / vmfPrice
        uint256 calculatedFee = (pricingConfig.baseEntryFee * pricingConfig.feeMultiplier) / vmfPrice;

        return calculatedFee;
    }

    /**
     * @dev Internal function to check price deviation
     */
    function _isPriceWithinDeviation(uint256 currentPrice) internal view returns (bool) {
        if (lastVMFPrice == 0) {
            return true;
        }

        uint256 deviation = currentPrice > lastVMFPrice ? 
            ((currentPrice - lastVMFPrice) * 100) / lastVMFPrice :
            ((lastVMFPrice - currentPrice) * 100) / lastVMFPrice;

        return deviation <= pricingConfig.maxPriceDeviation;
    }

    /**
     * @dev Internal function to record fee history
     */
    function _recordFeeHistory(uint256 vmfPrice, uint256 calculatedFee, uint256 actualFee) internal {
        FeeHistory memory history = FeeHistory({
            timestamp: block.timestamp,
            vmfPrice: vmfPrice,
            calculatedFee: calculatedFee,
            actualFee: actualFee,
            blockNumber: block.number
        });

        feeHistory[feeHistoryCount] = history;
        feeHistoryCount++;

        emit DynamicFeeCalculated(vmfPrice, calculatedFee, actualFee, block.timestamp);
    }
}

contracts/PizzaPartyLoyalty.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title PizzaPartyLoyalty
 * @dev Loyalty points system for Pizza Party game
 * 
 * FEATURES:
 * - Earn loyalty points for game participation
 * - Point redemption for rewards
 * - Tier-based loyalty system
 * - Point expiration management
 * - Loyalty analytics
 */
contract PizzaPartyLoyalty is ReentrancyGuard, Ownable, Pausable {

    // VMF Token contract
    IERC20 public immutable vmfToken;

    // Loyalty tier structure
    struct LoyaltyTier {
        string name;
        uint256 minPoints;
        uint256 maxPoints;
        uint256 rewardMultiplier;
        uint256 bonusRewards;
        bool isActive;
    }

    // User loyalty data
    struct UserLoyaltyData {
        uint256 totalPoints;
        uint256 currentTier;
        uint256 pointsEarned;
        uint256 pointsRedeemed;
        uint256 lastActivity;
        uint256 streakDays;
        uint256 totalRewards;
        bool isActive;
    }

    // Point transaction structure
    struct PointTransaction {
        uint256 timestamp;
        uint256 points;
        string reason;
        bool isEarned;
        uint256 tierAtTime;
    }

    // System constants
    uint256 public constant POINTS_PER_DOLLAR = 10; // 10 points per $1 spent
    uint256 public constant POINTS_PER_ENTRY = 5; // 5 points per game entry
    uint256 public constant STREAK_BONUS = 2; // 2 extra points per day in streak
    uint256 public constant MAX_STREAK_DAYS = 30; // Maximum streak bonus days
    uint256 public constant POINT_EXPIRY_DAYS = 365; // Points expire after 1 year

    // Loyalty tiers
    mapping(uint256 => LoyaltyTier) public loyaltyTiers;
    uint256 public tierCount;

    // User data
    mapping(address => UserLoyaltyData) public userLoyaltyData;
    mapping(address => PointTransaction[]) public userTransactions;
    mapping(address => bool) public blacklistedUsers;

    // Global tracking
    uint256 public totalPointsIssued;
    uint256 public totalPointsRedeemed;
    uint256 public totalUsers;
    uint256 public activeUsers;

    // Events
    event PointsEarned(
        address indexed user,
        uint256 points,
        string reason,
        uint256 newTotal,
        uint256 tier
    );

    event PointsRedeemed(
        address indexed user,
        uint256 points,
        uint256 rewardAmount,
        uint256 newTotal
    );

    event LoyaltyTierUpdated(
        address indexed user,
        uint256 oldTier,
        uint256 newTier,
        string tierName
    );

    event StreakUpdated(
        address indexed user,
        uint256 oldStreak,
        uint256 newStreak,
        uint256 bonusPoints
    );

    event TierCreated(
        uint256 tierId,
        string name,
        uint256 minPoints,
        uint256 maxPoints,
        uint256 rewardMultiplier
    );

    event UserBlacklisted(address indexed user, bool blacklisted);

    // Modifiers
    modifier notBlacklisted(address user) {
        require(!blacklistedUsers[user], "User is blacklisted");
        _;
    }

    modifier validTier(uint256 tierId) {
        require(tierId < tierCount, "Invalid tier ID");
        require(loyaltyTiers[tierId].isActive, "Tier is not active");
        _;
    }

    constructor(address _vmfToken) Ownable(msg.sender) {
        require(_vmfToken != address(0), "Invalid VMF token address");
        vmfToken = IERC20(_vmfToken);

        // Initialize default tiers
        _createDefaultTiers();
    }

    /**
     * @dev Award loyalty points to user
     */
    function awardLoyaltyPoints(
        address user,
        uint256 points,
        string memory reason
    ) external onlyOwner nonReentrant whenNotPaused notBlacklisted(user) {
        require(points > 0, "Points must be positive");
        require(user != address(0), "Invalid user address");

        UserLoyaltyData storage userData = userLoyaltyData[user];

        // Update user data
        userData.totalPoints += points;
        userData.pointsEarned += points;
        userData.lastActivity = block.timestamp;

        // Check for new user
        if (!userData.isActive) {
            userData.isActive = true;
            totalUsers++;
            activeUsers++;
        }

        // Update tier
        uint256 oldTier = userData.currentTier;
        uint256 newTier = _calculateTier(userData.totalPoints);
        userData.currentTier = newTier;

        // Update global stats
        totalPointsIssued += points;

        // Record transaction
        _recordTransaction(user, points, reason, true, newTier);

        // Emit events
        emit PointsEarned(user, points, reason, userData.totalPoints, newTier);

        if (oldTier != newTier) {
            emit LoyaltyTierUpdated(user, oldTier, newTier, loyaltyTiers[newTier].name);
        }
    }

    /**
     * @dev Award points for game entry
     */
    function awardEntryPoints(address user) external onlyOwner {
        require(user != address(0), "Invalid user address");

        uint256 basePoints = POINTS_PER_ENTRY;
        uint256 streakBonus = _calculateStreakBonus(user);
        uint256 totalPoints = basePoints + streakBonus;

        this.awardLoyaltyPoints(user, totalPoints, "Game Entry");

        // Update streak
        _updateStreak(user);
    }

    /**
     * @dev Award points for VMF spent
     */
    function awardSpendingPoints(address user, uint256 vmfAmount, uint256 vmfPrice) external onlyOwner {
        require(user != address(0), "Invalid user address");
        require(vmfAmount > 0, "Amount must be positive");
        require(vmfPrice > 0, "Price must be positive");

        // Calculate USD value
        uint256 usdValue = (vmfAmount * vmfPrice) / 10**18;

        // Calculate points based on USD value
        uint256 points = (usdValue * POINTS_PER_DOLLAR) / 10**18;

        if (points > 0) {
            this.awardLoyaltyPoints(user, points, "VMF Spending");
        }
    }

    /**
     * @dev Redeem points for VMF rewards
     */
    function redeemPoints(uint256 points) external nonReentrant whenNotPaused notBlacklisted(msg.sender) {
        require(points > 0, "Points must be positive");

        UserLoyaltyData storage userData = userLoyaltyData[msg.sender];
        require(userData.totalPoints >= points, "Insufficient points");

        // Calculate reward amount
        uint256 rewardAmount = _calculateRewardAmount(msg.sender, points);

        // Update user data
        userData.totalPoints -= points;
        userData.pointsRedeemed += points;
        userData.totalRewards += rewardAmount;

        // Update tier
        uint256 oldTier = userData.currentTier;
        uint256 newTier = _calculateTier(userData.totalPoints);
        userData.currentTier = newTier;

        // Update global stats
        totalPointsRedeemed += points;

        // Transfer reward
        require(vmfToken.transfer(msg.sender, rewardAmount), "Reward transfer failed");

        // Record transaction
        _recordTransaction(msg.sender, points, "Points Redemption", false, newTier);

        // Emit events
        emit PointsRedeemed(msg.sender, points, rewardAmount, userData.totalPoints);

        if (oldTier != newTier) {
            emit LoyaltyTierUpdated(msg.sender, oldTier, newTier, loyaltyTiers[newTier].name);
        }
    }

    /**
     * @dev Create new loyalty tier
     */
    function createLoyaltyTier(
        string memory name,
        uint256 minPoints,
        uint256 maxPoints,
        uint256 rewardMultiplier,
        uint256 bonusRewards
    ) external onlyOwner {
        require(bytes(name).length > 0, "Tier name cannot be empty");
        require(minPoints < maxPoints, "Invalid point range");
        require(rewardMultiplier > 0, "Reward multiplier must be positive");

        loyaltyTiers[tierCount] = LoyaltyTier({
            name: name,
            minPoints: minPoints,
            maxPoints: maxPoints,
            rewardMultiplier: rewardMultiplier,
            bonusRewards: bonusRewards,
            isActive: true
        });

        emit TierCreated(tierCount, name, minPoints, maxPoints, rewardMultiplier);
        tierCount++;
    }

    /**
     * @dev Update loyalty tier
     */
    function updateLoyaltyTier(
        uint256 tierId,
        string memory name,
        uint256 minPoints,
        uint256 maxPoints,
        uint256 rewardMultiplier,
        uint256 bonusRewards,
        bool isActive
    ) external onlyOwner validTier(tierId) {
        loyaltyTiers[tierId] = LoyaltyTier({
            name: name,
            minPoints: minPoints,
            maxPoints: maxPoints,
            rewardMultiplier: rewardMultiplier,
            bonusRewards: bonusRewards,
            isActive: isActive
        });
    }

    /**
     * @dev Get user loyalty data
     */
    function getUserLoyaltyData(address user) external view returns (UserLoyaltyData memory) {
        return userLoyaltyData[user];
    }

    /**
     * @dev Get user transactions
     */
    function getUserTransactions(address user, uint256 startIndex, uint256 count) 
        external 
        view 
        returns (PointTransaction[] memory)
    {
        PointTransaction[] storage transactions = userTransactions[user];
        require(startIndex < transactions.length, "Invalid start index");

        uint256 endIndex = startIndex + count;
        if (endIndex > transactions.length) {
            endIndex = transactions.length;
        }

        PointTransaction[] memory result = new PointTransaction[](endIndex - startIndex);

        for (uint256 i = startIndex; i < endIndex; i++) {
            result[i - startIndex] = transactions[i];
        }

        return result;
    }

    /**
     * @dev Get loyalty tier info
     */
    function getLoyaltyTier(uint256 tierId) external view validTier(tierId) returns (LoyaltyTier memory) {
        return loyaltyTiers[tierId];
    }

    /**
     * @dev Calculate reward amount for points
     */
    function calculateRewardAmount(address user, uint256 points) external view returns (uint256) {
        return _calculateRewardAmount(user, points);
    }

    /**
     * @dev Blacklist/unblacklist user
     */
    function setUserBlacklist(address user, bool blacklisted) external onlyOwner {
        blacklistedUsers[user] = blacklisted;
        emit UserBlacklisted(user, blacklisted);
    }

    /**
     * @dev Emergency pause/unpause
     */
    function emergencyPause(bool pause) external onlyOwner {
        if (pause) {
            _pause();
        } else {
            _unpause();
        }
    }

    /**
     * @dev Withdraw accumulated VMF (emergency only)
     */
    function emergencyWithdraw() external onlyOwner {
        uint256 balance = vmfToken.balanceOf(address(this));
        require(balance > 0, "No balance to withdraw");
        require(vmfToken.transfer(owner(), balance), "Withdrawal failed");
    }

    /**
     * @dev Internal function to create default tiers
     */
    function _createDefaultTiers() internal {
        // Bronze Tier
        loyaltyTiers[0] = LoyaltyTier({
            name: "Bronze",
            minPoints: 0,
            maxPoints: 999,
            rewardMultiplier: 100, // 1.0x
            bonusRewards: 0,
            isActive: true
        });

        // Silver Tier
        loyaltyTiers[1] = LoyaltyTier({
            name: "Silver",
            minPoints: 1000,
            maxPoints: 4999,
            rewardMultiplier: 120, // 1.2x
            bonusRewards: 10,
            isActive: true
        });

        // Gold Tier
        loyaltyTiers[2] = LoyaltyTier({
            name: "Gold",
            minPoints: 5000,
            maxPoints: 19999,
            rewardMultiplier: 150, // 1.5x
            bonusRewards: 25,
            isActive: true
        });

        // Platinum Tier
        loyaltyTiers[3] = LoyaltyTier({
            name: "Platinum",
            minPoints: 20000,
            maxPoints: type(uint256).max,
            rewardMultiplier: 200, // 2.0x
            bonusRewards: 50,
            isActive: true
        });

        tierCount = 4;
    }

    /**
     * @dev Internal function to calculate tier
     */
    function _calculateTier(uint256 points) internal view returns (uint256) {
        for (uint256 i = 0; i < tierCount; i++) {
            if (loyaltyTiers[i].isActive && 
                points >= loyaltyTiers[i].minPoints && 
                points <= loyaltyTiers[i].maxPoints) {
                return i;
            }
        }
        return 0; // Default to Bronze
    }

    /**
     * @dev Internal function to calculate reward amount
     */
    function _calculateRewardAmount(address user, uint256 points) internal view returns (uint256) {
        UserLoyaltyData storage userData = userLoyaltyData[user];
        uint256 tier = userData.currentTier;

        if (tier >= tierCount || !loyaltyTiers[tier].isActive) {
            tier = 0; // Default to Bronze
        }

        LoyaltyTier storage currentTier = loyaltyTiers[tier];

        // Base reward: 1 VMF per 100 points
        uint256 baseReward = (points * 10**18) / 100;

        // Apply tier multiplier
        uint256 tierReward = (baseReward * currentTier.rewardMultiplier) / 100;

        // Add bonus rewards
        uint256 bonusReward = currentTier.bonusRewards * 10**18;

        return tierReward + bonusReward;
    }

    /**
     * @dev Internal function to calculate streak bonus
     */
    function _calculateStreakBonus(address user) internal view returns (uint256) {
        UserLoyaltyData storage userData = userLoyaltyData[user];
        uint256 streakDays = userData.streakDays;

        if (streakDays > MAX_STREAK_DAYS) {
            streakDays = MAX_STREAK_DAYS;
        }

        return streakDays * STREAK_BONUS;
    }

    /**
     * @dev Internal function to update streak
     */
    function _updateStreak(address user) internal {
        UserLoyaltyData storage userData = userLoyaltyData[user];
        uint256 currentTime = block.timestamp;
        uint256 lastActivity = userData.lastActivity;

        // Check if activity is within 24 hours
        if (currentTime - lastActivity <= 1 days) {
            userData.streakDays++;
            if (userData.streakDays > MAX_STREAK_DAYS) {
                userData.streakDays = MAX_STREAK_DAYS;
            }
        } else {
            userData.streakDays = 1;
        }

        userData.lastActivity = currentTime;
    }

    /**
     * @dev Internal function to record transaction
     */
    function _recordTransaction(
        address user,
        uint256 points,
        string memory reason,
        bool isEarned,
        uint256 tier
    ) internal {
        PointTransaction memory transaction = PointTransaction({
            timestamp: block.timestamp,
            points: points,
            reason: reason,
            isEarned: isEarned,
            tierAtTime: tier
        });

        userTransactions[user].push(transaction);
    }
}

contracts/PizzaPartyReferral.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title PizzaPartyReferral
 * @dev Referral system for Pizza Party game
 * 
 * FEATURES:
 * - Create referral codes
 * - Process referrals
 * - Track referral rewards
 * - Referral analytics
 * - Anti-abuse measures
 */
contract PizzaPartyReferral is ReentrancyGuard, Ownable, Pausable {

    // VMF Token contract
    IERC20 public immutable vmfToken;

    // Referral code structure
    struct ReferralCode {
        bytes32 codeHash;
        address creator;
        uint256 expiry;
        bool claimed;
        uint256 claimCount;
        uint256 maxClaims;
        uint256 rewardAmount;
        string codeString;
        bool isActive;
    }

    // Referral claim structure
    struct ReferralClaim {
        address claimer;
        uint256 claimTime;
        uint256 rewardAmount;
        bool isProcessed;
    }

    // User referral data
    struct UserReferralData {
        uint256 totalCodesCreated;
        uint256 totalCodesClaimed;
        uint256 totalRewardsEarned;
        uint256 lastCodeGeneration;
        bool isBlacklisted;
        uint256 cooldownEndTime;
    }

    // System constants
    uint256 public constant CODE_EXPIRY_DURATION = 30 days;
    uint256 public constant MAX_CODE_LENGTH = 50;
    uint256 public constant MIN_CODE_LENGTH = 6;
    uint256 public constant MAX_CLAIMS_PER_CODE = 100;
    uint256 public constant GENERATION_COOLDOWN = 1 hours;
    uint256 public constant CLAIM_COOLDOWN = 30 minutes;
    uint256 public constant MAX_CODES_PER_USER = 10;

    // Default reward amounts
    uint256 public constant DEFAULT_REWARD_AMOUNT = 2; // 2 toppings
    uint256 public constant BONUS_REWARD_AMOUNT = 5; // 5 toppings for successful referrals

    // State variables
    mapping(bytes32 => ReferralCode) public referralCodes;
    mapping(address => UserReferralData) public userReferralData;
    mapping(address => bool) public blacklistedAddresses;
    mapping(bytes32 => ReferralClaim[]) public codeClaims;
    mapping(address => uint256) public userClaimCount;

    // Code generation tracking
    uint256 public totalCodesGenerated;
    uint256 public totalCodesClaimed;
    uint256 public totalRewardsDistributed;

    // Events
    event ReferralCodeGenerated(
        bytes32 indexed codeHash,
        address indexed creator,
        string codeString,
        uint256 expiry,
        uint256 maxClaims,
        uint256 rewardAmount
    );

    event ReferralCodeClaimed(
        bytes32 indexed codeHash,
        address indexed claimer,
        uint256 rewardAmount,
        uint256 claimTime
    );

    event ReferralRewardDistributed(
        address indexed referrer,
        address indexed referee,
        uint256 rewardAmount
    );

    event UserBlacklisted(address indexed user, bool blacklisted);

    // Modifiers
    modifier notBlacklisted(address user) {
        require(!blacklistedAddresses[user], "User is blacklisted");
        require(!userReferralData[user].isBlacklisted, "User is blacklisted");
        _;
    }

    modifier validReferralCode(string memory code) {
        require(bytes(code).length >= MIN_CODE_LENGTH, "Code too short");
        require(bytes(code).length <= MAX_CODE_LENGTH, "Code too long");
        require(_isValidReferralCodeFormat(code), "Invalid code format");
        _;
    }

    modifier codeExists(string memory code) {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        require(referralCodes[codeHash].isActive, "Referral code does not exist");
        _;
    }

    modifier codeNotExpired(string memory code) {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        require(block.timestamp < referralCodes[codeHash].expiry, "Referral code expired");
        _;
    }

    modifier codeNotClaimed(string memory code, address user) {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        require(!referralCodes[codeHash].claimed, "Code already claimed");
        require(userClaimCount[user] < MAX_CLAIMS_PER_CODE, "Max claims reached");
        _;
    }

    constructor(address _vmfToken) Ownable(msg.sender) {
        require(_vmfToken != address(0), "Invalid VMF token address");
        vmfToken = IERC20(_vmfToken);
    }

    /**
     * @dev Create a new referral code
     */
    function createReferralCode() external nonReentrant whenNotPaused notBlacklisted(msg.sender) {
        UserReferralData storage userData = userReferralData[msg.sender];

        // Check cooldown
        require(block.timestamp >= userData.cooldownEndTime, "Cooldown period active");

        // Check code limit
        require(userData.totalCodesCreated < MAX_CODES_PER_USER, "Max codes reached");

        // Generate referral code
        string memory code = _generateReferralCode(msg.sender);
        bytes32 codeHash = keccak256(abi.encodePacked(code));

        // Check if code already exists
        require(!referralCodes[codeHash].isActive, "Code already exists");

        // Create referral code
        referralCodes[codeHash] = ReferralCode({
            codeHash: codeHash,
            creator: msg.sender,
            expiry: block.timestamp + CODE_EXPIRY_DURATION,
            claimed: false,
            claimCount: 0,
            maxClaims: MAX_CLAIMS_PER_CODE,
            rewardAmount: DEFAULT_REWARD_AMOUNT,
            codeString: code,
            isActive: true
        });

        // Update user data
        userData.totalCodesCreated++;
        userData.lastCodeGeneration = block.timestamp;
        userData.cooldownEndTime = block.timestamp + GENERATION_COOLDOWN;

        // Update global stats
        totalCodesGenerated++;

        emit ReferralCodeGenerated(
            codeHash,
            msg.sender,
            code,
            block.timestamp + CODE_EXPIRY_DURATION,
            MAX_CLAIMS_PER_CODE,
            DEFAULT_REWARD_AMOUNT
        );
    }

    /**
     * @dev Process a referral code
     */
    function processReferralCode(string memory code, address user) 
        external 
        nonReentrant 
        whenNotPaused 
        validReferralCode(code)
        codeExists(code)
        codeNotExpired(code)
        codeNotClaimed(code, user)
        notBlacklisted(user)
    {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        ReferralCode storage referralCode = referralCodes[codeHash];

        // Check if user has already claimed this code
        require(userClaimCount[user] < referralCode.maxClaims, "Max claims reached");

        // Process the referral
        _processReferralCode(code, user);

        // Update claim count
        userClaimCount[user]++;
        referralCode.claimCount++;

        // Check if code should be marked as claimed
        if (referralCode.claimCount >= referralCode.maxClaims) {
            referralCode.claimed = true;
        }

        // Update global stats
        totalCodesClaimed++;

        emit ReferralCodeClaimed(
            codeHash,
            user,
            referralCode.rewardAmount,
            block.timestamp
        );
    }

    /**
     * @dev Get referral code info
     */
    function getReferralCodeInfo(string memory code) 
        external 
        view 
        validReferralCode(code)
        returns (ReferralCode memory)
    {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        return referralCodes[codeHash];
    }

    /**
     * @dev Get user referral data
     */
    function getUserReferralData(address user) external view returns (UserReferralData memory) {
        return userReferralData[user];
    }

    /**
     * @dev Get referral claims for a code
     */
    function getReferralClaims(string memory code) 
        external 
        view 
        validReferralCode(code)
        returns (ReferralClaim[] memory)
    {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        return codeClaims[codeHash];
    }

    /**
     * @dev Blacklist/unblacklist user
     */
    function setUserBlacklist(address user, bool blacklisted) external onlyOwner {
        blacklistedAddresses[user] = blacklisted;
        userReferralData[user].isBlacklisted = blacklisted;
        emit UserBlacklisted(user, blacklisted);
    }

    /**
     * @dev Emergency pause/unpause
     */
    function emergencyPause(bool pause) external onlyOwner {
        if (pause) {
            _pause();
        } else {
            _unpause();
        }
    }

    /**
     * @dev Withdraw accumulated VMF (emergency only)
     */
    function emergencyWithdraw() external onlyOwner {
        uint256 balance = vmfToken.balanceOf(address(this));
        require(balance > 0, "No balance to withdraw");
        require(vmfToken.transfer(owner(), balance), "Withdrawal failed");
    }

    /**
     * @dev Internal function to process referral code
     */
    function _processReferralCode(string memory code, address user) internal {
        bytes32 codeHash = keccak256(abi.encodePacked(code));
        ReferralCode storage referralCode = referralCodes[codeHash];

        // Create claim record
        ReferralClaim memory claim = ReferralClaim({
            claimer: user,
            claimTime: block.timestamp,
            rewardAmount: referralCode.rewardAmount,
            isProcessed: false
        });

        codeClaims[codeHash].push(claim);

        // Update user data
        UserReferralData storage userData = userReferralData[user];
        userData.totalCodesClaimed++;
        userData.totalRewardsEarned += referralCode.rewardAmount;

        // Update referrer data
        UserReferralData storage referrerData = userReferralData[referralCode.creator];
        referrerData.totalRewardsEarned += BONUS_REWARD_AMOUNT;

        // Transfer rewards
        if (vmfToken.balanceOf(address(this)) >= referralCode.rewardAmount + BONUS_REWARD_AMOUNT) {
            require(vmfToken.transfer(user, referralCode.rewardAmount), "Reward transfer failed");
            require(vmfToken.transfer(referralCode.creator, BONUS_REWARD_AMOUNT), "Bonus transfer failed");

            totalRewardsDistributed += referralCode.rewardAmount + BONUS_REWARD_AMOUNT;

            emit ReferralRewardDistributed(
                referralCode.creator,
                user,
                referralCode.rewardAmount + BONUS_REWARD_AMOUNT
            );
        }
    }

    /**
     * @dev Internal function to generate referral code
     */
    function _generateReferralCode(address user) internal view returns (string memory) {
        bytes32 hash = keccak256(abi.encodePacked(
            user,
            block.timestamp,
            block.prevrandao
        ));

        // Convert to alphanumeric string
        string memory chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
        bytes memory result = new bytes(MIN_CODE_LENGTH);

        for (uint256 i = 0; i < MIN_CODE_LENGTH; i++) {
            result[i] = bytes(chars)[uint8(hash[i]) % bytes(chars).length];
        }

        return string(result);
    }

    /**
     * @dev Internal function to validate referral code format
     */
    function _isValidReferralCodeFormat(string memory code) internal pure returns (bool) {
        bytes memory codeBytes = bytes(code);

        for (uint256 i = 0; i < codeBytes.length; i++) {
            bytes1 char = codeBytes[i];
            if (!((char >= 0x41 && char <= 0x5A) || // A-Z
                  (char >= 0x30 && char <= 0x39))) { // 0-9
                return false;
            }
        }

        return true;
    }
}

contracts/PizzaPartyWeeklyChallenges.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title PizzaPartyWeeklyChallenges
 * @dev Weekly challenges system for Pizza Party game
 * 
 * FEATURES:
 * - Weekly challenge creation and management
 * - Challenge completion tracking
 * - Reward distribution
 * - Challenge leaderboards
 * - Challenge categories and difficulty levels
 */
contract PizzaPartyWeeklyChallenges is ReentrancyGuard, Ownable, Pausable {

    // VMF Token contract
    IERC20 public immutable vmfToken;

    // Challenge structure
    struct Challenge {
        uint256 challengeId;
        string title;
        string description;
        uint256 rewardAmount;
        uint256 difficulty;
        uint256 startTime;
        uint256 endTime;
        uint256 maxParticipants;
        uint256 currentParticipants;
        bool isActive;
        bool isCompleted;
        string category;
        mapping(address => bool) participants;
        mapping(address => bool) completions;
        address[] participantList;
    }

    // User challenge data
    struct UserChallengeData {
        uint256 totalChallengesCompleted;
        uint256 totalRewardsEarned;
        uint256 currentStreak;
        uint256 longestStreak;
        uint256 lastCompletionTime;
        uint256 reputation;
        bool isActive;
    }

    // Challenge completion structure
    struct ChallengeCompletion {
        uint256 challengeId;
        address player;
        uint256 completionTime;
        uint256 rewardAmount;
        string proof;
        bool isVerified;
    }

    // System constants
    uint256 public constant CHALLENGE_DURATION = 7 days;
    uint256 public constant MIN_REWARD_AMOUNT = 10 * 10**18; // 10 VMF
    uint256 public constant MAX_REWARD_AMOUNT = 1000 * 10**18; // 1000 VMF
    uint256 public constant MAX_PARTICIPANTS = 1000;
    uint256 public constant STREAK_BONUS_MULTIPLIER = 10; // 10% bonus per streak week

    // Challenge tracking
    mapping(uint256 => Challenge) public challenges;
    uint256 public currentChallengeId;
    uint256 public totalChallenges;

    // User tracking
    mapping(address => UserChallengeData) public userChallengeData;
    mapping(address => ChallengeCompletion[]) public userCompletions;
    mapping(address => bool) public blacklistedUsers;

    // Category tracking
    mapping(string => uint256) public categoryChallengeCount;
    string[] public challengeCategories;

    // Global statistics
    uint256 public totalChallengesCompleted;
    uint256 public totalRewardsDistributed;
    uint256 public totalParticipants;
    uint256 public activeUsers;

    // Events
    event ChallengeCreated(
        uint256 indexed challengeId,
        string title,
        string category,
        uint256 rewardAmount,
        uint256 difficulty,
        uint256 startTime,
        uint256 endTime
    );

    event ChallengeJoined(
        uint256 indexed challengeId,
        address indexed player,
        uint256 timestamp
    );

    event ChallengeCompleted(
        uint256 indexed challengeId,
        address indexed player,
        uint256 rewardAmount,
        uint256 completionTime
    );

    event WeeklyChallengeCompleted(
        address indexed player,
        uint256 challengeId,
        uint256 reward,
        uint256 streak
    );

    event StreakUpdated(
        address indexed player,
        uint256 oldStreak,
        uint256 newStreak,
        uint256 bonusAmount
    );

    event CategoryCreated(string category);

    event UserBlacklisted(address indexed user, bool blacklisted);

    // Modifiers
    modifier notBlacklisted(address user) {
        require(!blacklistedUsers[user], "User is blacklisted");
        _;
    }

    modifier challengeExists(uint256 challengeId) {
        require(challengeId <= totalChallenges, "Challenge does not exist");
        _;
    }

    modifier challengeActive(uint256 challengeId) {
        require(challenges[challengeId].isActive, "Challenge is not active");
        require(block.timestamp >= challenges[challengeId].startTime, "Challenge not started");
        require(block.timestamp <= challenges[challengeId].endTime, "Challenge ended");
        _;
    }

    modifier notParticipated(uint256 challengeId, address player) {
        require(!challenges[challengeId].participants[player], "Already participated");
        _;
    }

    modifier notCompleted(uint256 challengeId, address player) {
        require(!challenges[challengeId].completions[player], "Already completed");
        _;
    }

    constructor(address _vmfToken) Ownable(msg.sender) {
        require(_vmfToken != address(0), "Invalid VMF token address");
        vmfToken = IERC20(_vmfToken);

        currentChallengeId = 1;
        totalChallenges = 0;

        // Initialize default categories
        _createDefaultCategories();
    }

    /**
     * @dev Create a new weekly challenge
     */
    function createChallenge(
        string memory title,
        string memory description,
        uint256 rewardAmount,
        uint256 difficulty,
        string memory category,
        uint256 maxParticipants
    ) external onlyOwner whenNotPaused {
        require(bytes(title).length > 0, "Title cannot be empty");
        require(bytes(description).length > 0, "Description cannot be empty");
        require(rewardAmount >= MIN_REWARD_AMOUNT, "Reward too low");
        require(rewardAmount <= MAX_REWARD_AMOUNT, "Reward too high");
        require(difficulty >= 1 && difficulty <= 5, "Invalid difficulty");
        require(maxParticipants > 0 && maxParticipants <= MAX_PARTICIPANTS, "Invalid max participants");

        uint256 challengeId = currentChallengeId;
        uint256 startTime = block.timestamp;
        uint256 endTime = startTime + CHALLENGE_DURATION;

        Challenge storage challenge = challenges[challengeId];
        challenge.challengeId = challengeId;
        challenge.title = title;
        challenge.description = description;
        challenge.rewardAmount = rewardAmount;
        challenge.difficulty = difficulty;
        challenge.startTime = startTime;
        challenge.endTime = endTime;
        challenge.maxParticipants = maxParticipants;
        challenge.currentParticipants = 0;
        challenge.isActive = true;
        challenge.isCompleted = false;
        challenge.category = category;

        currentChallengeId++;
        totalChallenges++;

        // Update category count
        if (categoryChallengeCount[category] == 0) {
            challengeCategories.push(category);
        }
        categoryChallengeCount[category]++;

        emit ChallengeCreated(
            challengeId,
            title,
            category,
            rewardAmount,
            difficulty,
            startTime,
            endTime
        );
    }

    /**
     * @dev Join a challenge
     */
    function joinChallenge(uint256 challengeId) 
        external 
        nonReentrant 
        whenNotPaused 
        challengeExists(challengeId)
        challengeActive(challengeId)
        notParticipated(challengeId, msg.sender)
        notBlacklisted(msg.sender)
    {
        Challenge storage challenge = challenges[challengeId];

        require(challenge.currentParticipants < challenge.maxParticipants, "Challenge full");

        // Record participation
        challenge.participants[msg.sender] = true;
        challenge.participantList.push(msg.sender);
        challenge.currentParticipants++;

        // Update user data
        UserChallengeData storage userData = userChallengeData[msg.sender];
        if (!userData.isActive) {
            userData.isActive = true;
            totalParticipants++;
            activeUsers++;
        }

        emit ChallengeJoined(challengeId, msg.sender, block.timestamp);
    }

    /**
     * @dev Complete a challenge
     */
    function completeChallenge(uint256 challengeId, string memory proof) 
        external 
        nonReentrant 
        whenNotPaused 
        challengeExists(challengeId)
        challengeActive(challengeId)
        notCompleted(challengeId, msg.sender)
    {
        require(challenges[challengeId].participants[msg.sender], "Not participating");

        Challenge storage challenge = challenges[challengeId];

        // Record completion
        challenge.completions[msg.sender] = true;

        // Calculate reward with streak bonus
        uint256 baseReward = challenge.rewardAmount;
        uint256 streakBonus = _calculateStreakBonus(msg.sender);
        uint256 totalReward = baseReward + streakBonus;

        // Update user data
        UserChallengeData storage userData = userChallengeData[msg.sender];
        userData.totalChallengesCompleted++;
        userData.totalRewardsEarned += totalReward;
        userData.lastCompletionTime = block.timestamp;
        userData.reputation += challenge.difficulty;

        // Update streak
        _updateStreak(msg.sender);

        // Update global stats
        totalChallengesCompleted++;
        totalRewardsDistributed += totalReward;

        // Record completion
        ChallengeCompletion memory completion = ChallengeCompletion({
            challengeId: challengeId,
            player: msg.sender,
            completionTime: block.timestamp,
            rewardAmount: totalReward,
            proof: proof,
            isVerified: true
        });

        userCompletions[msg.sender].push(completion);

        // Transfer reward
        require(vmfToken.transfer(msg.sender, totalReward), "Reward transfer failed");

        emit ChallengeCompleted(challengeId, msg.sender, totalReward, block.timestamp);
        emit WeeklyChallengeCompleted(msg.sender, challengeId, totalReward, userData.currentStreak);
    }

    /**
     * @dev Get challenge info
     */
    function getChallengeInfo(uint256 challengeId) 
        external 
        view 
        challengeExists(challengeId)
        returns (
            string memory title,
            string memory description,
            uint256 rewardAmount,
            uint256 difficulty,
            uint256 startTime,
            uint256 endTime,
            uint256 maxParticipants,
            uint256 currentParticipants,
            bool isActive,
            bool isCompleted,
            string memory category
        )
    {
        Challenge storage challenge = challenges[challengeId];
        return (
            challenge.title,
            challenge.description,
            challenge.rewardAmount,
            challenge.difficulty,
            challenge.startTime,
            challenge.endTime,
            challenge.maxParticipants,
            challenge.currentParticipants,
            challenge.isActive,
            challenge.isCompleted,
            challenge.category
        );
    }

    /**
     * @dev Get user challenge data
     */
    function getUserChallengeData(address user) external view returns (UserChallengeData memory) {
        return userChallengeData[user];
    }

    /**
     * @dev Get user completions
     */
    function getUserCompletions(address user, uint256 startIndex, uint256 count) 
        external 
        view 
        returns (ChallengeCompletion[] memory)
    {
        ChallengeCompletion[] storage completions = userCompletions[user];
        require(startIndex < completions.length, "Invalid start index");

        uint256 endIndex = startIndex + count;
        if (endIndex > completions.length) {
            endIndex = completions.length;
        }

        ChallengeCompletion[] memory result = new ChallengeCompletion[](endIndex - startIndex);

        for (uint256 i = startIndex; i < endIndex; i++) {
            result[i - startIndex] = completions[i];
        }

        return result;
    }

    /**
     * @dev Get challenge participants
     */
    function getChallengeParticipants(uint256 challengeId) 
        external 
        view 
        challengeExists(challengeId)
        returns (address[] memory)
    {
        return challenges[challengeId].participantList;
    }

    /**
     * @dev Get challenge categories
     */
    function getChallengeCategories() external view returns (string[] memory) {
        return challengeCategories;
    }

    /**
     * @dev Update challenge status
     */
    function updateChallengeStatus(uint256 challengeId, bool isActive) 
        external 
        onlyOwner 
        challengeExists(challengeId)
    {
        challenges[challengeId].isActive = isActive;
    }

    /**
     * @dev Blacklist/unblacklist user
     */
    function setUserBlacklist(address user, bool blacklisted) external onlyOwner {
        blacklistedUsers[user] = blacklisted;
        emit UserBlacklisted(user, blacklisted);
    }

    /**
     * @dev Emergency pause/unpause
     */
    function emergencyPause(bool pause) external onlyOwner {
        if (pause) {
            _pause();
        } else {
            _unpause();
        }
    }

    /**
     * @dev Withdraw accumulated VMF (emergency only)
     */
    function emergencyWithdraw() external onlyOwner {
        uint256 balance = vmfToken.balanceOf(address(this));
        require(balance > 0, "No balance to withdraw");
        require(vmfToken.transfer(owner(), balance), "Withdrawal failed");
    }

    /**
     * @dev Internal function to create default categories
     */
    function _createDefaultCategories() internal {
        challengeCategories.push("Daily");
        challengeCategories.push("Weekly");
        challengeCategories.push("Social");
        challengeCategories.push("Trading");
        challengeCategories.push("Community");

        for (uint256 i = 0; i < challengeCategories.length; i++) {
            categoryChallengeCount[challengeCategories[i]] = 0;
            emit CategoryCreated(challengeCategories[i]);
        }
    }

    /**
     * @dev Internal function to calculate streak bonus
     */
    function _calculateStreakBonus(address user) internal view returns (uint256) {
        UserChallengeData storage userData = userChallengeData[user];
        uint256 streak = userData.currentStreak;

        if (streak == 0) return 0;

        // 10% bonus per week of streak
        uint256 bonusPercentage = streak * STREAK_BONUS_MULTIPLIER;
        return (challenges[currentChallengeId - 1].rewardAmount * bonusPercentage) / 100;
    }

    /**
     * @dev Internal function to update streak
     */
    function _updateStreak(address user) internal {
        UserChallengeData storage userData = userChallengeData[user];
        uint256 currentTime = block.timestamp;
        uint256 lastCompletion = userData.lastCompletionTime;

        // Check if completion is within 7 days of last completion
        if (currentTime - lastCompletion <= CHALLENGE_DURATION) {
            userData.currentStreak++;
            if (userData.currentStreak > userData.longestStreak) {
                userData.longestStreak = userData.currentStreak;
            }
        } else {
            userData.currentStreak = 1;
        }

        userData.lastCompletionTime = currentTime;
    }
}

